export type CanonicalJobCategory =
 | 'tech'
 | 'finance'
 | 'health'
 | 'engineering'
 | 'admin'
 | 'hospitality'
 | 'sales'
 | 'other';

export type CanonicalContractType = 'full-time' | 'part-time' | 'temporary' | 'internship' | 'contract';

